import { DEFAULT_EMPTY_VALUE, GB, KB, MB, TB, EMPTY_SET, currencySymbolMap } from '../const';
import { CurrencyOption, CurrencyPatternMap, IdentifierType, UnitOption } from '../type';
import { getSiteTenantCurrencyCode, getSiteTenantCurrencySymbol } from './siteTenant';

/**
 * 格式化工具
 * - 数据大小
 * - 金额
 * - 数字
 */

/**
 * 数据大小格式化工具
 */
export const dataSizeFormatter = <{ (size: number): string }>function (size: number) {
    if (size > TB) {
        return `${(size / TB).toFixed(2)} TB`;
    }
    if (size > GB) {
        return `${(size / GB).toFixed(2)} GB`;
    }
    if (size > MB) {
        return `${(size / MB).toFixed(2)} MB`;
    }
    return `${(size / KB).toFixed(2)} KB`;
};

/**
 * 金额格式化工具
 * @deprecated 【请勿使用，已废弃，未来即将移除】仅兼容旧代码，新的金额/货币格式化工具请使用 formatCurrency
 * @param amount
 * @param decimal
 */
export function amountFormatter(amount?: IdentifierType, decimal = 2): string {
    return amount || String(amount) === '0'
        ? Number.parseFloat(String(amount)).toLocaleString('en-US', {
              minimumFractionDigits: decimal,
              maximumFractionDigits: decimal
          })
        : DEFAULT_EMPTY_VALUE;
}

/**
 * 单位格式化工具 【测试版本】
 * @param digit
 * @param opt 可以直接传string作为单位；也可传`UnitOption`作为配置
 */
export function formatUnit(digit?: IdentifierType, opt?: UnitOption | string): string {
    if (EMPTY_SET.has(digit)) return DEFAULT_EMPTY_VALUE;

    const {
        decimal = 0,
        unit = '',
        pattern = 'DU',
        transform
    } = typeof opt === 'string' ? ({ unit: opt } as UnitOption) : opt ?? {};
    const temp = {
        U: unit,
        D: amountFormatter(transform ? transform(digit) : digit, decimal)
    };
    return pattern.replace(/[DU]/g, (res) => temp[res as keyof typeof temp]);
}

/** 空数据格式化工具 */
export function formatEmpty<T = any, U = string>(
    value: T,
    empty = DEFAULT_EMPTY_VALUE as unknown as U
) {
    return EMPTY_SET.has(value) ? empty : value;
}

/**
 * @description: 获取货币符号
 * @param {string} code
 */
export function getCurrencySymbol(code: string) {
    return currencySymbolMap[code];
}

/**
 * 货币格式化工具
 */
export class CurrencyFormatter {
    private code: string;
    private pattern: string;
    private decimal: number;
    private empty: Set<any>;
    private symbol: string;

    /**
     * @param opt
     */
    constructor(opt?: CurrencyOption) {
        this.decimal = opt?.decimal ?? 2;
        this.pattern = opt?.pattern ?? 'SD';
        this.code = opt?.code ?? getSiteTenantCurrencyCode();
        this.empty = opt?.emptySet ?? EMPTY_SET;
        this.symbol = opt?.symbol ?? getSiteTenantCurrencySymbol();
    }

    /**
     * 获取当前货币符号
     */
    public getSymbol = () => this.symbol;

    /**
     * 数字格式化
     * @param amount
     * @param decimal
     */
    public amount = (amount?: IdentifierType, decimal = this.decimal) =>
        !this.empty.has(amount)
            ? Number.parseFloat(String(amount)).toLocaleString('en-US', {
                  minimumFractionDigits: decimal,
                  maximumFractionDigits: decimal
              })
            : DEFAULT_EMPTY_VALUE;
    /**
     * 货币格式化
     * @param amount
     * @param code
     * @param opt [opt]
     */
    public format = (
        amount?: IdentifierType,
        opt?: Pick<CurrencyOption, 'decimal' | 'pattern' | 'code'>
    ) => {
        if (this.empty.has(amount)) return DEFAULT_EMPTY_VALUE;

        const {
            decimal = this.decimal,
            pattern = this.pattern,
            code = opt?.code ?? this.code
        } = { ...opt };
        const temp: CurrencyPatternMap = {
            C: code,
            S: this.symbol,
            D: this.amount(amount, decimal)
        };
        return pattern.replace(/[CDS]/g, (res) => temp[res as keyof typeof temp]);
    };
}

/**
 * 数字格式化工具
 * @param number
 * @param decimal
 */
export function formatNumber(number: number | string | undefined | null, decimal = 2) {
    return number !== null && !Number.isNaN(+number!)
        ? Number.parseFloat(String(number)).toFixed(decimal)
        : DEFAULT_EMPTY_VALUE;
}

/**
 * 排序参数格式化（与后端保持一致）
 * @param {Record} sort
 */
export const sortQueryFormatter = (sort: Record<string, any>) => {
    if (sort) {
        const [column] = Object.keys(sort);
        return { column, sortType: sort[column] };
    }
    return {};
};

/**
 * 体积格式化
 * @param {number} volume
 * @param {number} [decimal=2]
 * @return {*}
 */
export const formatVolume = (volume: number, decimal = 6) =>
    formatUnit(volume, { pattern: 'D U', unit: 'cbm', decimal });

/**
 * 重量格式化
 * @param {number} weight
 * @param {number} [decimal=2]
 * @return {*}
 */
export const formatWeight = (weight: number, decimal = 2) =>
    formatUnit(weight, { pattern: 'D U', unit: 'lb', decimal });

/**
 * 长度格式化
 * @param {number} weight
 * @param {number} [decimal=2]
 */
export const formatLength = (weight: number, decimal = 2) =>
    formatUnit(weight, { pattern: 'D U', unit: 'inch', decimal });

/**
 * 仓库名称格式化
 * @param {Record<string, any>} [r]
 */
export const formatStorageName = (r?: Record<string, any>) =>
    !!r?.storageName || !!r?.storageCode
        ? `${r.storageName}(${r.storageCode})`
        : DEFAULT_EMPTY_VALUE;


/**
 * 将itemKey转换为合法的className
 * 使用\w匹配字母数字下划线,优化正则表达式
 */
export const convertToValidClassName = (key: string) => {
    return key.replace(/[^\w-]/g, '-');
};